"use strict";

require("./libs/tabs");
var menu = document.querySelector('.menu');
var menuOpenBtn = document.querySelector('.open-menu-btn');
var menuBg = document.querySelector('.menu__bg');
if (menu) {
  menuOpenBtn.addEventListener('click', function (ev) {
    menu.classList.add('_visible');
    document.body.classList.add('no-scroll');
  });
  menuBg.addEventListener('click', function (ev) {
    menu.classList.remove('_visible');
    document.body.classList.remove('no-scroll');
  });
}
if (document.querySelector('.products')) {
  var products = tabs({
    el: ".products",
    tabNavigationLinks: '.products__nav-btn',
    tabContentContainers: '.products__content'
  });
  products.init();
}

